+  /**
+   * Partial dot product using only first N dimensions (for screening)
+   */
+  private partialDotProduct(a: Float32Array, b: Float32Array, len: number): number {
+    let sum = 0;
+    let i = 0;
+    for (; i <= len - 4; i += 4) {
+      sum += a[i] * b[i] + a[i + 1] * b[i + 1] + a[i + 2] * b[i + 2] + a[i + 3] * b[i + 3];
+    }
+    for (; i < len; i++) {
+      sum += a[i] * b[i];
+    }
+    return sum;
+  }
+
